function longestCommonSubsequence(data) {
    const [str1, str2] = data.split('\n');
    function lcsHelper(i, j) {
        if (i < 0 || j < 0) return 0;
        if (str1[i] === str2[j]) {
            return 1 + lcsHelper(i - 1, j - 1);
        } else {
            return Math.max(lcsHelper(i - 1, j), lcsHelper(i, j - 1));
        }
    }
    return lcsHelper(str1.length - 1, str2.length - 1);
}

