func longestCommonSubsequence(data string) int {
    strs := splitData(data)
    return lcs(strs[0], strs[1])
}

func splitData(data string) []string {
    // Assuming the input format is "string1,string2"
    return strings.Split(data, ",")
}

func lcs(x, y string) int {
    return lcsHelper(x, y, len(x), len(y))
}

func lcsHelper(x, y string, m, n int) int {
    if m == 0 || n == 0 {
        return 0
    }
    if x[m-1] == y[n-1] {
        return 1 + lcsHelper(x, y, m-1, n-1)
    }
    return max(lcsHelper(x, y, m-1, n), lcsHelper(x, y, m, n-1))
}

func max(a, b int) int {
    if a > b {
        return a
    }
    return b
}

func main() {
    data := "abcde,ace" // Example input
    fmt.Println(longestCommonSubsequence(data))
}

